/* RISC-V boot entry. OpenSBI hands off in S-mode with:
 *   a0 = hartid, a1 = device-tree blob pointer.
 * Only hart 0 runs the kernel; other harts park.
 */
    .section .text.boot, "ax"
    .globl _start
_start:
    /* Park secondary harts. */
    bnez    a0, park

    /* Set up the boot stack (top of the reserved region). */
    la      sp, boot_stack_top

    /* Zero the BSS. */
    la      t0, __bss_start
    la      t1, __bss_end
1:
    bgeu    t0, t1, 2f
    sd      zero, 0(t0)
    addi    t0, t0, 8

