/* Virtual-address layout constants shared by C and assembly.
 *
 * The kernel is identity-mapped in low memory. Each user process additionally
 * maps a trampoline page (shared trap entry/exit code) and its trapframe at the
 * top of the Sv39 address space, exactly as in xv6. satp is switched between
 * the user and kernel page tables inside the trampoline.
 */
#ifndef _KERNEL_MEMLAYOUT_H
#define _KERNEL_MEMLAYOUT_H

#ifdef __ASSEMBLER__
#define MAXVA      (1 << 38)
#else
#define MAXVA      (1UL << 38)
#endif

#define TRAMPOLINE   (MAXVA - 4096)
#define TRAPFRAME    (TRAMPOLINE - 4096)

/* User stack: a reserved window below the trapframe, populated on demand. */
#define USTACK_PAGES 1024
#define USTACK_INITIAL_PAGES 16
#define USTACK_TOP   TRAPFRAME

#endif /* _KERNEL_MEMLAYOUT_H */
